  7→	"github.com/spf13/cobra"
  8→	"github.com/usenurge/nurgesh/internal/config"
  9→	"github.com/usenurge/nurgesh/internal/db"
 10→	"github.com/usenurge/nurgesh/internal/emails"
 11→	"github.com/usenurge/nurgesh/internal/learning"
 12→)
 13→
 14→var hookCmd = &cobra.Command{
 15→	Use:         "hook",
 16→	Short:       "Claude Code hook handlers (internal)",
 17→	Hidden:      true,
 18→	Annotations: map[string]string{"skipAuth": "true"},
 19→}
 20→
 21→var hookPostToolUseCmd = &cobra.Command{
 22→	Use:   "post-tool-use",
 23→	Short: "Handle post-tool-use hook events",
 24→	RunE: func(cmd *cobra.Command, args []string) error {
 25→		// No-op for now. Future: capture session context.
 26→		return nil
 27→	},
 28→}
 29→
 30→var hookSessionStartBannerCmd = &cobra.Command{
 31→	Use:   "session-start-banner",
 32→	Short: "Output branded banner for SessionStart hook",
 33→	RunE: func(cmd *cobra.Command, args []string) error {
 34→		return runSessionStartBanner()
 35→	},
 36→}
 37→
 38→var hookSessionStartPromptCmd = &cobra.Command{
 39→	Use:   "session-start-prompt",
 40→	Short: "Output Claude instructions for SessionStart hook",
 41→	RunE: func(cmd *cobra.Command, args []string) error {
 42→		return runSessionStartPrompt()
 43→	},
 44→}
 45→
 46→func init() {
 47→	hookCmd.AddCommand(hookPostToolUseCmd)
 48→	hookCmd.AddCommand(hookSessionStartBannerCmd)
 49→	hookCmd.AddCommand(hookSessionStartPromptCmd)
 50→	rootCmd.AddCommand(hookCmd)
 51→}
 52→
 53→// sessionStatus holds workspace state gathered for banner/prompt output.
 54→type sessionStatus struct {
 55→	configLoaded   bool
 56→	setupCompleted bool
 57→	connectors     map[string]config.ConnectorState
 58→	emailTotal     int
 59→	skillCount     int
 60→	skillNames     []string
 61→}
 62→
 63→func gatherStatus() *sessionStatus {
 64→	s := &sessionStatus{}
 65→
 66→	// Load config (graceful — may not exist)
 67→	cfg, err := config.Load()
 68→	if err == nil {
 69→		s.configLoaded = true
 70→		s.setupCompleted = cfg.SetupCompleted
 71→		s.connectors = cfg.Connectors
 72→	}
 73→
 74→	// Load DB stats (graceful — may not exist)
 75→	if !db.Exists() {
 76→		return s
 77→	}
 78→	d, err := db.Open()
 79→	if err != nil {
 80→		return s
 81→	}
 82→	defer d.Close()
 83→
 84→	stats, err := emails.Stats(d)
 85→	if err == nil {
 86→		s.emailTotal = stats.Total
 87→	}
 88→
 89→	skills, err := learning.ListSkills(d)
 90→	if err == nil {
 91→		s.skillCount = len(skills)
 92→		for _, sk := range skills {
 93→			s.skillNames = append(s.skillNames, sk.SkillName)
 94→		}
 95→	}
 96→
