package cmd

import (
	"fmt"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/config"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/emails"
	"github.com/usenurge/nurgesh/internal/learning"
)

var hookCmd = &cobra.Command{
	Use:         "hook",
	Short:       "Claude Code hook handlers (internal)",
	Hidden:      true,
	Annotations: map[string]string{"skipAuth": "true"},
}

var hookPostToolUseCmd = &cobra.Command{
	Use:   "post-tool-use",
	Short: "Handle post-tool-use hook events",
	RunE: func(cmd *cobra.Command, args []string) error {
		// No-op for now. Future: capture session context.
		return nil
	},
}

var hookSessionStartBannerCmd = &cobra.Command{
	Use:   "session-start-banner",
	Short: "Output branded banner for SessionStart hook",
	RunE: func(cmd *cobra.Command, args []string) error {
		return runSessionStartBanner()
	},
}

var hookSessionStartPromptCmd = &cobra.Command{
	Use:   "session-start-prompt",
	Short: "Output Claude instructions for SessionStart hook",
	RunE: func(cmd *cobra.Command, args []string) error {
		return runSessionStartPrompt()
	},
}

func init() {
	hookCmd.AddCommand(hookPostToolUseCmd)
	hookCmd.AddCommand(hookSessionStartBannerCmd)
	hookCmd.AddCommand(hookSessionStartPromptCmd)
	rootCmd.AddCommand(hookCmd)
}

// sessionStatus holds workspace state gathered for banner/prompt output.
type sessionStatus struct {
	configLoaded   bool
	setupCompleted bool
	connectors     map[string]config.ConnectorState
	emailTotal     int
	skillCount     int
	skillNames     []string
}

func gatherStatus() *sessionStatus {
	s := &sessionStatus{}

	// Load config (graceful — may not exist)
	cfg, err := config.Load()
	if err == nil {
		s.configLoaded = true
		s.setupCompleted = cfg.SetupCompleted
		s.connectors = cfg.Connectors
	}

	// Load DB stats (graceful — may not exist)
	if !db.Exists() {
		return s
	}
	d, err := db.Open()
	if err != nil {
		return s
	}
	defer d.Close()

	stats, err := emails.Stats(d)
	if err == nil {
		s.emailTotal = stats.Total
	}

	skills, err := learning.ListSkills(d)
	if err == nil {
		s.skillCount = len(skills)
		for _, sk := range skills {
			s.skillNames = append(s.skillNames, sk.SkillName)
		}
	}

	return s
}

func runSessionStartBanner() error {
	s := gatherStatus()

	fmt.Println("⚡ Powered by Nurge")
	fmt.Println()

	if !s.configLoaded {
		fmt.Println("  Run: nurge init to get started")
		return nil
	}

	// Connectors
	hasConnectors := false
	for id, c := range s.connectors {
		if !c.Connected {
			continue
		}
		hasConnectors = true
		switch c.Type {
		case "email":
			fmt.Printf("  %s: %s (%s emails synced)\n", capitalize(id), c.Account, formatCount(s.emailTotal))
		case "crm":
			fmt.Printf("  %s: connected\n", capitalize(id))
		}
	}

	if !hasConnectors {
		fmt.Println("  No connectors configured.")
		fmt.Println("  Run: nurge init --force to reconnect")
		return nil
	}

	// Skills
	fmt.Printf("  Skills: %d active\n", s.skillCount)
	fmt.Println()

	if s.setupCompleted {
		fmt.Println("  Try:")
		fmt.Println("    \"Write a cold email to the CTO at Datastack\"")
		fmt.Println("    \"Research Acme Corp and qualify them\"")
		fmt.Println("    \"Show my pipeline\"")
	} else {
		fmt.Println("  Run /nurge:setup to get started")
	}

	return nil
}

func runSessionStartPrompt() error {
	s := gatherStatus()

	if !s.configLoaded || !s.setupCompleted {
		fmt.Println("You are in a Nurge workspace. Setup is not complete.")
		fmt.Println("Guide the user to run /nurge:setup to finish configuration.")
		fmt.Println("Do not attempt to use nurge data commands — they will have no data yet.")
		return nil
	}

	fmt.Println("You are in a Nurge outbound sales workspace.")
	fmt.Println()
	fmt.Printf("Status: Setup complete. %s emails synced. %d skills active.\n", formatCount(s.emailTotal), s.skillCount)
	fmt.Println()
	fmt.Println("Rules:")
	fmt.Println("- Use `nurge` CLI commands for all data access. Never read .nurge/ directly.")
	fmt.Println("- For ICP and product context, run: nurge config show --format json")
	fmt.Println("- For email patterns and insights, run: nurge context generate --format json")
	fmt.Println("- For email stats, run: nurge emails stats --format json")
	fmt.Println("- When writing outbound emails, always run: nurge send")

	if len(s.skillNames) > 0 {
		fmt.Println()
		fmt.Printf("Available skills: %s\n", strings.Join(s.skillNames, ", "))
	}

	return nil
}

func capitalize(s string) string {
	if s == "" {
		return s
	}
	return strings.ToUpper(s[:1]) + s[1:]
}

func formatCount(n int) string {
	if n >= 1000 {
		return fmt.Sprintf("%d,%03d", n/1000, n%1000)
	}
	return fmt.Sprintf("%d", n)
}

