  1→package init
  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"os"
  7→	"path/filepath"
  8→)
  9→
 10→type hooksStep struct{}
 11→
 12→func (s *hooksStep) Name() string { return "Claude Code hooks installed" }
 13→
 14→// requiredHooks defines all hooks nurge needs installed.
 15→var requiredHooks = []struct {
 16→	event   string // "PostToolUse" or "SessionStart"
 17→	command string
 18→	htype   string // "command" or "prompt"
 19→	timeout int
 20→	matcher string // empty means no matcher
 21→}{
 22→	{event: "PostToolUse", command: "nurge hook post-tool-use", htype: "command", timeout: 5, matcher: "Bash"},
 23→	{event: "SessionStart", command: "nurge hook session-start-banner", htype: "command", timeout: 10},
 24→	{event: "SessionStart", command: "nurge hook session-start-prompt", htype: "command", timeout: 10},
 25→}
 26→
 27→func (s *hooksStep) Done() (bool, error) {
 28→	data, err := os.ReadFile(claudeSettingsPath())
 29→	if err != nil {
 30→		if os.IsNotExist(err) {
 31→			return false, nil
 32→		}
 33→		return false, err
 34→	}
 35→
 36→	var settings map[string]any
 37→	if err := json.Unmarshal(data, &settings); err != nil {
 38→		return false, nil
 39→	}
 40→
 41→	hooks, ok := settings["hooks"].(map[string]any)
 42→	if !ok {
 43→		return false, nil
 44→	}
 45→
 46→	// All required hooks must be present
 47→	for _, rh := range requiredHooks {
 48→		if !hookCommandExists(hooks, rh.event, rh.command) {
 49→			return false, nil
 50→		}
 51→	}
 52→	return true, nil
 53→}
 54→
 55→func (s *hooksStep) Run() error {
 56→	settingsPath := claudeSettingsPath()
 57→
 58→	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
 59→		return fmt.Errorf("creating .claude/: %w", err)
 60→	}
 61→
 62→	// Load existing settings or start fresh
 63→	settings := make(map[string]any)
 64→	if data, err := os.ReadFile(settingsPath); err == nil {
 65→		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
 66→	}
 67→
 68→	hooks, _ := settings["hooks"].(map[string]any)
 69→	if hooks == nil {
 70→		hooks = make(map[string]any)
 71→	}
 72→
 73→	// Add each required hook if not already present
 74→	for _, rh := range requiredHooks {
 75→		if hookCommandExists(hooks, rh.event, rh.command) {
 76→			continue
 77→		}
 78→
 79→		entry := map[string]any{
 80→			"hooks": []any{
 81→				map[string]any{
 82→					"type":    rh.htype,
 83→					"command": rh.command,
 84→					"timeout": rh.timeout,
 85→				},
 86→			},
 87→		}
 88→		if rh.matcher != "" {
 89→			entry["matcher"] = rh.matcher
 90→		}
 91→
 92→		eventHooks, _ := hooks[rh.event].([]any)
 93→		eventHooks = append(eventHooks, entry)
 94→		hooks[rh.event] = eventHooks
 95→	}
 96→
 97→	settings["hooks"] = hooks
 98→
 99→	// Set permissions so nurge commands and skill edits don't prompt
100→	permissions, _ := settings["permissions"].(map[string]any)
101→	if permissions == nil {
102→		permissions = make(map[string]any)
103→	}
104→	allow, _ := permissions["allow"].([]any)
105→	requiredPerms := []string{
106→		"Bash(nurge *)",
107→		"Read",
108→		"Edit(.claude/skills/**)",
109→	}
110→	for _, perm := range requiredPerms {
111→		if !containsString(allow, perm) {
112→			allow = append(allow, perm)
113→		}
114→	}
115→	permissions["allow"] = allow
116→	settings["permissions"] = permissions
117→
118→	data, err := json.MarshalIndent(settings, "", "  ")
119→	if err != nil {
120→		return fmt.Errorf("marshaling settings: %w", err)
121→	}
122→
123→	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
124→		return fmt.Errorf("writing settings: %w", err)
125→	}
126→
127→	return nil
128→}
129→
130→// hookCommandExists checks if a specific command already exists under the given event key.
131→func hookCommandExists(hooks map[string]any, event, command string) bool {
132→	arr, ok := hooks[event].([]any)
133→	if !ok {
134→		return false
135→	}
136→	for _, item := range arr {
137→		m, ok := item.(map[string]any)
138→		if !ok {
139→			continue
140→		}
141→		innerHooks, ok := m["hooks"].([]any)
142→		if !ok {
143→			continue
