package init

import (
	"os"
	"os/exec"
)

type gitStep struct{}

func (s *gitStep) Name() string { return "Git repository initialized" }

func (s *gitStep) Done() (bool, error) {
	// Done if .git exists AND has at least one commit
	if _, err := os.Stat(".git"); err != nil {
		return false, nil
	}
	cmd := exec.Command("git", "rev-parse", "HEAD")
	cmd.Stdout = nil
	cmd.Stderr = nil
	return cmd.Run() == nil, nil
}

func (s *gitStep) Run() error {
	// Init if needed
	if _, err := os.Stat(".git"); err != nil {
		cmd := exec.Command("git", "init", "-q")
		cmd.Stdout = os.Stdout
		cmd.Stderr = os.Stderr
		if err := cmd.Run(); err != nil {
			return err
		}
	}

	// Initial commit so Claude Code recognizes the project
	add := exec.Command("git", "add", "-A")
	add.Stdout = os.Stdout
	add.Stderr = os.Stderr
	if err := add.Run(); err != nil {
		return err
	}

	commit := exec.Command("git", "commit", "-q", "-m", "nurge init")
	commit.Stdout = os.Stdout
	commit.Stderr = os.Stderr
	return commit.Run()
}

