package session

import (
	"context"
	"fmt"
	"log/slog"
	"strings"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/logging"
)

// Phase represents the lifecycle stage of a session.
type Phase string

const (
	PhaseActive Phase = "active"
	PhaseIdle   Phase = "idle"
	PhaseEnded  Phase = "ended"
)

// allPhases is the canonical list of phases for enumeration (e.g., diagram generation).
var allPhases = []Phase{PhaseIdle, PhaseActive, PhaseEnded}

// PhaseFromString normalizes a phase string, treating empty or unknown values
// as PhaseIdle for backward compatibility with pre-state-machine session files.
func PhaseFromString(s string) Phase {
	switch Phase(s) {
	case PhaseActive, "active_committed":
		// "active_committed" was removed with the 1:1 checkpoint model.
		// It previously meant "agent active + commit happened during turn".
		// Normalize to ACTIVE so HandleTurnEnd can finalize any pending checkpoints.
		return PhaseActive
	case PhaseIdle:
		return PhaseIdle
	case PhaseEnded:
		return PhaseEnded
	default:
		// Backward compat: truly unknown phases normalize to idle.
		return PhaseIdle
	}
}

// IsActive reports whether the phase represents an active agent turn.
func (p Phase) IsActive() bool {
	return p == PhaseActive
}

// Event represents something that happened to a session.
type Event int

const (
	EventTurnStart    Event = iota // Agent begins working on a prompt
	EventTurnEnd                   // Agent finishes its turn
	EventGitCommit                 // A git commit was made (PostCommit hook)
	EventSessionStart              // Session process started (SessionStart hook)
	EventSessionStop               // Session process ended (SessionStop hook)
	EventCompaction                // Agent compacted context mid-turn (PreCompress hook)
)

// allEvents is the canonical list of events for enumeration.
var allEvents = []Event{EventTurnStart, EventTurnEnd, EventGitCommit, EventSessionStart, EventSessionStop, EventCompaction}

// String returns a human-readable name for the event.
func (e Event) String() string {
	switch e {
	case EventTurnStart:
		return "TurnStart"
	case EventTurnEnd:
		return "TurnEnd"
	case EventGitCommit:
		return "GitCommit"
	case EventSessionStart:
		return "SessionStart"
	case EventSessionStop:
		return "SessionStop"
	case EventCompaction:
		return "Compaction"
	default:
		return fmt.Sprintf("Event(%d)", int(e))
	}
}

// Action represents a side effect that should be performed after a transition.
// The caller is responsible for executing these -- the state machine only declares them.
type Action int

const (
	ActionCondense               Action = iota // Condense session data to permanent storage
	ActionCondenseIfFilesTouched               // Condense only if FilesTouched is non-empty
	ActionDiscardIfNoFiles                     // Discard session if FilesTouched is empty
	ActionWarnStaleSession                     // Warn user about stale session(s)
	ActionClearEndedAt                         // Clear EndedAt timestamp (session re-entering)
	ActionUpdateLastInteraction                // Update LastInteractionTime
)

// String returns a human-readable name for the action.
func (a Action) String() string {
	switch a {
	case ActionCondense:
		return "Condense"
	case ActionCondenseIfFilesTouched:
		return "CondenseIfFilesTouched"
	case ActionDiscardIfNoFiles:
		return "DiscardIfNoFiles"
	case ActionWarnStaleSession:
		return "WarnStaleSession"
	case ActionClearEndedAt:
		return "ClearEndedAt"
	case ActionUpdateLastInteraction:
		return "UpdateLastInteraction"
	default:
		return fmt.Sprintf("Action(%d)", int(a))
	}
}

// TransitionContext provides read-only context for transitions that need
// to inspect session state without mutating it.
type TransitionContext struct {
	HasFilesTouched    bool // len(FilesTouched) > 0
	IsRebaseInProgress bool // .git/rebase-merge/ or .git/rebase-apply/ exists
}

// TransitionResult holds the outcome of a state machine transition.
type TransitionResult struct {
	NewPhase Phase
	Actions  []Action
}

// Transition computes the next phase and required actions given the current
// phase and an event. This is a pure function with no side effects.
//
// Empty or unknown phase values are normalized to PhaseIdle for backward
// compatibility with session state files created before phase tracking.
func Transition(current Phase, event Event, ctx TransitionContext) TransitionResult {
	// Normalize empty/unknown phase to idle for backward compatibility.
	current = PhaseFromString(string(current))

	switch current {
	case PhaseIdle:
		return transitionFromIdle(event, ctx)
	case PhaseActive:
		return transitionFromActive(event, ctx)
	case PhaseEnded:
		return transitionFromEnded(event, ctx)
	default:
		// PhaseFromString guarantees we only get known phases, but the
		// exhaustive linter requires handling the default case.
		return TransitionResult{NewPhase: PhaseIdle}
	}
}

func transitionFromIdle(event Event, ctx TransitionContext) TransitionResult {
	switch event {
	case EventTurnStart:
		return TransitionResult{
			NewPhase: PhaseActive,
			Actions:  []Action{ActionUpdateLastInteraction},
		}
	case EventTurnEnd:
		// Turn end while idle is a no-op (no active turn to end).
		return TransitionResult{NewPhase: PhaseIdle}
	case EventGitCommit:
		if ctx.IsRebaseInProgress {
			return TransitionResult{NewPhase: PhaseIdle}
		}
		return TransitionResult{
			NewPhase: PhaseIdle,
			Actions:  []Action{ActionCondense},
		}
	case EventSessionStart:
		// Already condensable, no-op.
		return TransitionResult{NewPhase: PhaseIdle}
	case EventSessionStop:
		return TransitionResult{
			NewPhase: PhaseEnded,
			Actions:  []Action{ActionUpdateLastInteraction},
		}
	case EventCompaction:
		// Compaction while idle shouldn't happen, but condense if there's work.
		return TransitionResult{
			NewPhase: PhaseIdle,
			Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
		}
	default:
		return TransitionResult{NewPhase: PhaseIdle}
	}
}

func transitionFromActive(event Event, ctx TransitionContext) TransitionResult {
	switch event {
	case EventTurnStart:
		// Ctrl-C recovery: agent crashed or user interrupted mid-turn.
		return TransitionResult{
			NewPhase: PhaseActive,
			Actions:  []Action{ActionUpdateLastInteraction},
		}
	case EventTurnEnd:
		return TransitionResult{
			NewPhase: PhaseIdle,
			Actions:  []Action{ActionUpdateLastInteraction},
		}
	case EventGitCommit:
		if ctx.IsRebaseInProgress {
			return TransitionResult{NewPhase: PhaseActive}
		}
		return TransitionResult{
			NewPhase: PhaseActive,
			Actions:  []Action{ActionCondense},
		}
	case EventSessionStart:
		return TransitionResult{
			NewPhase: PhaseActive,
			Actions:  []Action{ActionWarnStaleSession},
		}
	case EventSessionStop:
		return TransitionResult{
			NewPhase: PhaseEnded,
			Actions:  []Action{ActionUpdateLastInteraction},
		}
	case EventCompaction:
		// Compaction mid-turn: save current progress but stay active.
		// The transcript offset will be reset by the compaction handler.
		return TransitionResult{
			NewPhase: PhaseActive,
			Actions:  []Action{ActionCondenseIfFilesTouched, ActionUpdateLastInteraction},
		}
	default:
		return TransitionResult{NewPhase: PhaseActive}
	}
}

func transitionFromEnded(event Event, ctx TransitionContext) TransitionResult {
	switch event {
	case EventTurnStart:
		return TransitionResult{
			NewPhase: PhaseActive,
			Actions:  []Action{ActionClearEndedAt, ActionUpdateLastInteraction},
		}
	case EventTurnEnd:
		// Turn end while ended is a no-op.
		return TransitionResult{NewPhase: PhaseEnded}
	case EventGitCommit:
		if ctx.IsRebaseInProgress {
			return TransitionResult{NewPhase: PhaseEnded}
		}
		if ctx.HasFilesTouched {
			return TransitionResult{
				NewPhase: PhaseEnded,
				Actions:  []Action{ActionCondenseIfFilesTouched},
			}
		}
		return TransitionResult{
			NewPhase: PhaseEnded,
			Actions:  []Action{ActionDiscardIfNoFiles},
		}
	case EventSessionStart:
		return TransitionResult{
			NewPhase: PhaseIdle,
			Actions:  []Action{ActionClearEndedAt},
		}
	case EventSessionStop:
		// Already ended, no-op.
		return TransitionResult{NewPhase: PhaseEnded}
	case EventCompaction:
		// Compaction while ended shouldn't happen, no-op.
		return TransitionResult{NewPhase: PhaseEnded}
	default:
		return TransitionResult{NewPhase: PhaseEnded}
	}
}

// ActionHandler defines strategy-specific side effects for state transitions.
// The compiler enforces that every strategy-specific action has a handler.
type ActionHandler interface {
	HandleCondense(state *State) error
	HandleCondenseIfFilesTouched(state *State) error
	HandleDiscardIfNoFiles(state *State) error
	HandleWarnStaleSession(state *State) error
}

// NoOpActionHandler is a default ActionHandler where all methods are no-ops.
// Embed this in handler structs to only override the methods you need.
type NoOpActionHandler struct{}

func (NoOpActionHandler) HandleCondense(_ *State) error               { return nil }
func (NoOpActionHandler) HandleCondenseIfFilesTouched(_ *State) error { return nil }
func (NoOpActionHandler) HandleDiscardIfNoFiles(_ *State) error       { return nil }
func (NoOpActionHandler) HandleWarnStaleSession(_ *State) error       { return nil }

// ApplyTransition applies a TransitionResult to state: sets the new phase
// unconditionally, then executes all actions. Common actions
// (UpdateLastInteraction, ClearEndedAt) always run regardless of handler
// errors so that bookkeeping fields stay consistent with the new phase.
// Strategy-specific handler actions stop on the first error; subsequent
// handler actions are skipped but common actions continue. Returns the
// first handler error, or nil.
func ApplyTransition(ctx context.Context, state *State, result TransitionResult, handler ActionHandler) error {
	logCtx := logging.WithComponent(ctx, "session")

	actionStrs := make([]string, len(result.Actions))
	for i, a := range result.Actions {
		actionStrs[i] = a.String()
	}
	logging.Debug(logCtx, "ApplyTransition",
		slog.String("session_id", state.SessionID),
		slog.String("old_phase", string(state.Phase)),
		slog.String("new_phase", string(result.NewPhase)),
		slog.String("actions", strings.Join(actionStrs, ",")),
	)

	state.Phase = result.NewPhase

	var handlerErr error
	for _, action := range result.Actions {
		switch action {
		// Common actions: always applied, even after a handler error.
		case ActionUpdateLastInteraction:
			now := time.Now()
			state.LastInteractionTime = &now
		case ActionClearEndedAt:
			state.EndedAt = nil
			state.FullyCondensed = false

		// Strategy-specific actions: skip remaining after the first handler error.
		case ActionCondense:
			if handlerErr == nil {
				if err := handler.HandleCondense(state); err != nil {
					handlerErr = fmt.Errorf("%s: %w", action, err)
				}
			}
		case ActionCondenseIfFilesTouched:
			if handlerErr == nil {
				if err := handler.HandleCondenseIfFilesTouched(state); err != nil {
					handlerErr = fmt.Errorf("%s: %w", action, err)
				}
			}
		case ActionDiscardIfNoFiles:
			if handlerErr == nil {
				if err := handler.HandleDiscardIfNoFiles(state); err != nil {
					handlerErr = fmt.Errorf("%s: %w", action, err)
				}
			}
		case ActionWarnStaleSession:
			if handlerErr == nil {
				if err := handler.HandleWarnStaleSession(state); err != nil {
					handlerErr = fmt.Errorf("%s: %w", action, err)
				}
			}
		default:
			if handlerErr == nil {
				handlerErr = fmt.Errorf("unhandled action: %s", action)
			}
		}
	}
	return handlerErr
}

// MermaidDiagram generates a Mermaid state diagram from the transition table.
// The diagram is derived by calling Transition() for representative context
// variants per phase/event, so it stays in sync with the implementation.
func MermaidDiagram() string {
	var b strings.Builder
	b.WriteString("stateDiagram-v2\n")

	// State declarations with descriptions.
	b.WriteString("    state \"IDLE\" as idle\n")
	b.WriteString("    state \"ACTIVE\" as active\n")
	b.WriteString("    state \"ENDED\" as ended\n")
	b.WriteString("\n")

	// Context variants for GitCommit: rebase, files/no-files.
	type contextVariant struct {
		label string
		ctx   TransitionContext
	}

	// For each phase/event, generate edges.
	for _, phase := range allPhases {
		for _, event := range allEvents {
			var variants []contextVariant
			switch {
			case event == EventGitCommit && phase == PhaseEnded:
				// HasFilesTouched only affects PhaseEnded transitions;
				// other phases produce identical edges for both values.
				variants = []contextVariant{
					{"[files]", TransitionContext{HasFilesTouched: true}},
					{"[no files]", TransitionContext{HasFilesTouched: false}},
					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
				}
			case event == EventGitCommit:
				variants = []contextVariant{
					{"", TransitionContext{}},
					{"[rebase]", TransitionContext{IsRebaseInProgress: true}},
				}
			default:
				variants = []contextVariant{
					{"", TransitionContext{}},
				}
			}

			for _, v := range variants {
				result := Transition(phase, event, v.ctx)

				// Build edge label.
				label := event.String()
				if v.label != "" {
					label += " " + v.label
				}
				if len(result.Actions) > 0 {
					actionNames := make([]string, 0, len(result.Actions))
					for _, a := range result.Actions {
						actionNames = append(actionNames, a.String())
					}
					label += " / " + strings.Join(actionNames, ", ")
				}

				from := string(phase)
				to := string(result.NewPhase)

				fmt.Fprintf(&b, "    %s --> %s : %s\n", from, to, label)
			}
		}
	}

	return b.String()
}

package strategy

import (
	"context"
	"encoding/json"
	"fmt"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/checkpoint"
	"github.com/entireio/cli/cmd/entire/cli/checkpoint/id"
	"github.com/entireio/cli/cmd/entire/cli/paths"

	"github.com/go-git/go-git/v6"
)

// NoDescription is the default description for sessions without one.
const NoDescription = "No description"

// Session represents a Claude Code session with its checkpoints.
// A session is created when a user runs `claude` and tracks all changes
// made during that interaction.
type Session struct {
	// ID is the unique session identifier (e.g., "2025-12-01-8f76b0e8-b8f1-4a87-9186-848bdd83d62e")
	ID string

	// Description is a human-readable summary of the session
	// (typically the first prompt or derived from commit messages)
	Description string

	// Strategy is the name of the strategy that created this session
	Strategy string

	// StartTime is when the session was started
	StartTime time.Time

	// Checkpoints is the list of save points within this session
	Checkpoints []Checkpoint
}

// Checkpoint represents a save point within a session.
// Checkpoints can be either session-level (on Stop) or task-level (on subagent completion).
type Checkpoint struct {
	// CheckpointID is the stable 12-hex-char identifier for this checkpoint.
	// Used to look up metadata at <id[:2]>/<id[2:]>/ on entire/checkpoints/v1 branch.
	CheckpointID id.CheckpointID

	// Message is the commit message or checkpoint description
	Message string

	// Timestamp is when this checkpoint was created
	Timestamp time.Time

	// IsTaskCheckpoint indicates if this is a task checkpoint (vs a session checkpoint)
	IsTaskCheckpoint bool

	// ToolUseID is the tool use ID for task checkpoints (empty for session checkpoints)
	ToolUseID string
}

// ListSessions returns all sessions from the entire/checkpoints/v1 branch,
// plus any additional sessions from strategies implementing SessionSource.
// It automatically discovers all registered strategies and merges their sessions.
func ListSessions(ctx context.Context) ([]Session, error) {
	repo, err := OpenRepository(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to open git repository: %w", err)
	}

	// Get checkpoints from the entire/checkpoints/v1 branch
	checkpoints, err := ListCheckpoints(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to list checkpoints: %w", err)
	}

	// Group checkpoints by session ID
	// For multi-session checkpoints, expand SessionIDs array so each session gets the checkpoint
	sessionMap := make(map[string]*Session)
	for _, cp := range checkpoints {
		// Determine which session IDs this checkpoint belongs to
		// Multi-session checkpoints have SessionIDs populated; single-session use SessionID
		sessionIDs := cp.SessionIDs
		if len(sessionIDs) == 0 {
			sessionIDs = []string{cp.SessionID}
		}

		for _, sessionID := range sessionIDs {
			if sessionID == "" {
				continue
			}

			if existing, ok := sessionMap[sessionID]; ok {
				existing.Checkpoints = append(existing.Checkpoints, Checkpoint{
					CheckpointID:     cp.CheckpointID,
					Message:          "Checkpoint: " + cp.CheckpointID.String(),
					Timestamp:        cp.CreatedAt,
					IsTaskCheckpoint: cp.IsTask,
					ToolUseID:        cp.ToolUseID,
				})
			} else {
				// Get description from the checkpoint tree
				description := getDescriptionForCheckpoint(repo, cp.CheckpointID)

				sessionMap[sessionID] = &Session{
					ID:          sessionID,
					Description: description,
					Strategy:    "", // Will be set from metadata if available
					StartTime:   cp.CreatedAt,
					Checkpoints: []Checkpoint{{
						CheckpointID:     cp.CheckpointID,
						Message:          "Checkpoint: " + cp.CheckpointID.String(),
						Timestamp:        cp.CreatedAt,
						IsTaskCheckpoint: cp.IsTask,
						ToolUseID:        cp.ToolUseID,
					}},
				}
			}
		}
	}

	// Check for additional sessions
	strat := NewManualCommitStrategy()
	if additionalSessions, err := strat.GetAdditionalSessions(ctx); err == nil {
		for _, addSession := range additionalSessions {
			if addSession == nil {
				continue
			}
			if existing, ok := sessionMap[addSession.ID]; ok {
				// Merge checkpoints - deduplicate by CheckpointID
				existingCPIDs := make(map[string]bool)
				for _, cp := range existing.Checkpoints {
					existingCPIDs[cp.CheckpointID.String()] = true
				}
				for _, cp := range addSession.Checkpoints {
					if !existingCPIDs[cp.CheckpointID.String()] {
						existing.Checkpoints = append(existing.Checkpoints, cp)
					}
				}
				// Update start time if additional session is older
				if addSession.StartTime.Before(existing.StartTime) {
					existing.StartTime = addSession.StartTime
				}
				// Use description from additional source if existing is empty
				if existing.Description == "" || existing.Description == NoDescription {
					existing.Description = addSession.Description
				}
			} else {
				// New session from additional source
				sessionMap[addSession.ID] = addSession
			}
		}
	}

	// Convert map to slice
	sessions := make([]Session, 0, len(sessionMap))
	for _, session := range sessionMap {
		// Sort checkpoints within each session by timestamp (most recent first)
		sort.Slice(session.Checkpoints, func(i, j int) bool {
			return session.Checkpoints[i].Timestamp.After(session.Checkpoints[j].Timestamp)
		})
		sessions = append(sessions, *session)
	}

	// Sort sessions by start time (most recent first)
	sort.Slice(sessions, func(i, j int) bool {
		return sessions[i].StartTime.After(sessions[j].StartTime)
	})

	return sessions, nil
}

// GetSession finds a session by ID (supports prefix matching).
// Returns ErrNoSession if no matching session is found.
func GetSession(ctx context.Context, sessionID string) (*Session, error) {
	sessions, err := ListSessions(ctx)
	if err != nil {
		return nil, err
	}
	return findSessionByID(sessions, sessionID)
}

// getDescriptionForCheckpoint reads the description for a checkpoint from the entire/checkpoints/v1 branch.
// It reads from the latest session subdirectory in the new storage format.
func getDescriptionForCheckpoint(repo *git.Repository, checkpointID id.CheckpointID) string {
	tree, err := GetMetadataBranchTree(repo)
	if err != nil {
		return NoDescription
	}

	// Get the checkpoint tree
	checkpointTree, err := tree.Tree(checkpointID.Path())
	if err != nil {
		return NoDescription
	}

	// Read root metadata.json to get session count and sessions map
	metadataFile, err := checkpointTree.File(paths.MetadataFileName)
	if err != nil {
		return NoDescription
	}

	content, err := metadataFile.Contents()
	if err != nil {
		return NoDescription
	}

	var summary checkpoint.CheckpointSummary
	if err := json.Unmarshal([]byte(content), &summary); err != nil {
		return NoDescription
	}

	// Find the first session's prompt/context path
	// Try to use the latest session for description (0-based indexing)
	sessionDir := "0"
	if len(summary.Sessions) > 0 {
		sessionDir = strconv.Itoa(len(summary.Sessions) - 1) // Use latest session
	}

	sessionTree, err := checkpointTree.Tree(sessionDir)
	if err != nil {
		return NoDescription
	}

	return getSessionDescriptionFromTree(sessionTree, "")
}

// findSessionByID finds a session by exact ID or prefix match.
func findSessionByID(sessions []Session, sessionID string) (*Session, error) {
	for _, session := range sessions {
		if session.ID == sessionID || strings.HasPrefix(session.ID, sessionID) {
			return &session, nil
		}
	}
	return nil, ErrNoSession
}

package strategy

import (
	"context"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"sync"

	"github.com/entireio/cli/cmd/entire/cli/settings"
)

// Hook marker used to identify Entire CLI hooks
const entireHookMarker = "Entire CLI hooks"

const backupSuffix = ".pre-entire"
const chainComment = "# Chain: run pre-existing hook"

// gitHookNames are the git hooks managed by Entire CLI
var gitHookNames = []string{"prepare-commit-msg", "commit-msg", "post-commit", "pre-push"}

// ManagedGitHookNames returns the list of git hooks managed by Entire CLI.
// This is useful for tests that need to manipulate hooks.
func ManagedGitHookNames() []string {
	return gitHookNames
}

// hookSpec defines a git hook's name and content template (without chain call).
type hookSpec struct {
	name    string
	content string
}

// GetGitDir returns the actual git directory path by delegating to git itself.
// This handles both regular repositories and worktrees, and inherits git's
// security validation for gitdir references.
func GetGitDir(ctx context.Context) (string, error) {
	return getGitDirInPath(ctx, ".")
}

// hooksDirCache caches the hooks directory to avoid repeated git subprocess spawns.
// Keyed by current working directory to handle directory changes.
var (
	hooksDirMu       sync.RWMutex
	hooksDirCache    string
	hooksDirCacheDir string
)

// GetHooksDir returns the active hooks directory path.
// This respects core.hooksPath and correctly resolves to the common hooks
// directory when called from a linked worktree.
// The result is cached per working directory.
func GetHooksDir(ctx context.Context) (string, error) {
	cwd, err := os.Getwd() //nolint:forbidigo // cache key for hooks dir, same pattern as paths.WorktreeRoot()
	if err != nil {
		cwd = ""
	}

	hooksDirMu.RLock()
	if hooksDirCache != "" && hooksDirCacheDir == cwd {
		cached := hooksDirCache
		hooksDirMu.RUnlock()
		return cached, nil
	}
	hooksDirMu.RUnlock()

	result, err := getHooksDirInPath(ctx, ".")
	if err != nil {
		return "", err
	}

	hooksDirMu.Lock()
	hooksDirCache = result
	hooksDirCacheDir = cwd
	hooksDirMu.Unlock()

	return result, nil
}

// ClearHooksDirCache clears the cached hooks directory.
// This is primarily useful for testing when changing directories.
func ClearHooksDirCache() {
	hooksDirMu.Lock()
	hooksDirCache = ""
	hooksDirCacheDir = ""
	hooksDirMu.Unlock()
}

// getGitDirInPath returns the git directory for a repository at the given path.
// It delegates to `git rev-parse --git-dir` to leverage git's own validation.
func getGitDirInPath(ctx context.Context, dir string) (string, error) {
	cmd := exec.CommandContext(ctx, "git", "rev-parse", "--git-dir")
	cmd.Dir = dir
	output, err := cmd.Output()
	if err != nil {
		return "", errors.New("not a git repository")
	}

	gitDir := strings.TrimSpace(string(output))

	// git rev-parse --git-dir returns relative paths from the working directory,
	// so we need to make it absolute if it isn't already
	if !filepath.IsAbs(gitDir) {
		gitDir = filepath.Join(dir, gitDir)
	}

	return filepath.Clean(gitDir), nil
}

// getHooksDirInPath returns the active hooks directory for a repository at the given path.
// It delegates to `git rev-parse --git-path hooks` so Git resolves:
// - linked-worktree common hooks directory
// - core.hooksPath (relative or absolute)
func getHooksDirInPath(ctx context.Context, dir string) (string, error) {
	cmd := exec.CommandContext(ctx, "git", "rev-parse", "--git-path", "hooks")
	cmd.Dir = dir
	output, err := cmd.Output()
	if err != nil {
		return "", errors.New("not a git repository")
	}

	hooksDir := strings.TrimSpace(string(output))
	if !filepath.IsAbs(hooksDir) {
		hooksDir = filepath.Join(dir, hooksDir)
	}

	return filepath.Clean(hooksDir), nil
}

// IsGitHookInstalled checks if all generic Entire CLI hooks are installed.
func IsGitHookInstalled(ctx context.Context) bool {
	hooksDir, err := GetHooksDir(ctx)
	if err != nil {
		return false
	}
	return isGitHookInstalledInHooksDir(hooksDir)
}

// IsGitHookInstalledInDir checks if all Entire CLI hooks are installed in the given repo directory.
// This is useful for tests that need to check hooks without changing the working directory.
func IsGitHookInstalledInDir(ctx context.Context, repoDir string) bool {
	hooksDir, err := getHooksDirInPath(ctx, repoDir)
	if err != nil {
		return false
	}
	return isGitHookInstalledInHooksDir(hooksDir)
}

// isGitHookInstalledInHooksDir checks if all hooks are installed in the given hooks directory.
func isGitHookInstalledInHooksDir(hooksDir string) bool {
	for _, hook := range gitHookNames {
		hookPath := filepath.Join(hooksDir, hook)
		data, err := os.ReadFile(hookPath) //nolint:gosec // Path is constructed from constants
		if err != nil {
			return false
		}
		if !strings.Contains(string(data), entireHookMarker) {
			return false
		}
	}
	return true
}

// buildHookSpecs returns the hook specifications for all managed hooks.
func buildHookSpecs(cmdPrefix string) []hookSpec {
	return []hookSpec{
		{
			name: "prepare-commit-msg",
			content: fmt.Sprintf(`#!/bin/sh
# %s
%s hooks git prepare-commit-msg "$1" "$2" 2>/dev/null || true
`, entireHookMarker, cmdPrefix),
		},
		{
			name: "commit-msg",
			content: fmt.Sprintf(`#!/bin/sh
# %s
# Commit-msg hook: strip trailer if no user content (allows aborting empty commits)
%s hooks git commit-msg "$1" || exit 1
`, entireHookMarker, cmdPrefix),
		},
		{
			name: "post-commit",
			content: fmt.Sprintf(`#!/bin/sh
# %s
# Post-commit hook: condense session data if commit has Entire-Checkpoint trailer
%s hooks git post-commit 2>/dev/null || true
`, entireHookMarker, cmdPrefix),
		},
		{
			name: "pre-push",
			content: fmt.Sprintf(`#!/bin/sh
# %s
# Pre-push hook: push session logs alongside user's push
# $1 is the remote name (e.g., "origin")
%s hooks git pre-push "$1" || true
`, entireHookMarker, cmdPrefix),
		},
	}
}

// InstallGitHook installs generic git hooks that delegate to `entire hook` commands.
// These hooks work with any strategy - the strategy is determined at runtime.
// If silent is true, no output is printed (except backup notifications, which always print).
// localDev controls whether hooks use "go run" (true) or the "entire" binary (false).
// absolutePath embeds the full binary path in hooks for GUI git clients.
// Returns the number of hooks that were installed (0 if all already up to date).
func InstallGitHook(ctx context.Context, silent, localDev, absolutePath bool) (int, error) {
	hooksDir, err := GetHooksDir(ctx)
	if err != nil {
		return 0, err
	}

	if err := os.MkdirAll(hooksDir, 0o755); err != nil { //nolint:gosec // Git hooks require executable permissions
		return 0, fmt.Errorf("failed to create hooks directory: %w", err)
	}

	cmdPrefix, err := hookCmdPrefix(localDev, absolutePath)
	if err != nil {
		return 0, err
	}
	specs := buildHookSpecs(cmdPrefix)
	installedCount := 0

	for _, spec := range specs {
		hookPath := filepath.Join(hooksDir, spec.name)
		backupPath := hookPath + backupSuffix
		backupExists := fileExists(backupPath)

		// Back up existing non-Entire hooks
		existing, existingErr := os.ReadFile(hookPath) //nolint:gosec // path is controlled
		if existingErr == nil && !strings.Contains(string(existing), entireHookMarker) {
			if !backupExists {
				if err := os.Rename(hookPath, backupPath); err != nil {
					return installedCount, fmt.Errorf("failed to back up %s: %w", spec.name, err)
				}
				fmt.Fprintf(os.Stderr, "[entire] Backed up existing %s to %s%s\n", spec.name, spec.name, backupSuffix)
			} else {
				fmt.Fprintf(os.Stderr, "[entire] Warning: replacing %s (backup %s%s already exists from a previous install)\n", spec.name, spec.name, backupSuffix)
			}
			backupExists = true
		}

		// Chain to backup if one exists
		content := spec.content
		if backupExists {
			content = generateChainedContent(spec.content, spec.name)
		}

		written, err := writeHookFile(hookPath, content)
		if err != nil {
			return installedCount, fmt.Errorf("failed to install %s hook: %w", spec.name, err)
		}
		if written {
			installedCount++
		}
	}

	if !silent {
		fmt.Println("✓ Installed git hooks (prepare-commit-msg, commit-msg, post-commit, pre-push)")
		fmt.Println("  Hooks delegate to the current strategy at runtime")
	}

	return installedCount, nil
}

// writeHookFile writes a hook file if it doesn't exist or has different content.
// Returns true if the file was written, false if it already had the same content.
func writeHookFile(path, content string) (bool, error) {
	// Check if file already exists with same content
	existing, err := os.ReadFile(path) //nolint:gosec // path is controlled
	if err == nil && string(existing) == content {
		return false, nil // Already up to date
	}

	// Git hooks must be executable (0o755)
	if err := os.WriteFile(path, []byte(content), 0o755); err != nil { //nolint:gosec // Git hooks require executable permissions
		return false, fmt.Errorf("failed to write hook file %s: %w", path, err)
	}
	return true, nil
}

// RemoveGitHook removes all Entire CLI git hooks from the repository.
// If a .pre-entire backup exists, it is restored.
// Returns the number of hooks removed.
func RemoveGitHook(ctx context.Context) (int, error) {
	hooksDir, err := GetHooksDir(ctx)
	if err != nil {
		return 0, err
	}

	removed := 0
	var removeErrors []string

	for _, hook := range gitHookNames {
		hookPath := filepath.Join(hooksDir, hook)
		backupPath := hookPath + backupSuffix

		// Remove the hook if it contains our marker
		data, err := os.ReadFile(hookPath) //nolint:gosec // path is controlled
		hookIsOurs := err == nil && strings.Contains(string(data), entireHookMarker)
		hookExists := err == nil

		if hookIsOurs {
			if err := os.Remove(hookPath); err != nil {
				removeErrors = append(removeErrors, fmt.Sprintf("%s: %v", hook, err))
				continue
			}
			removed++
		}

		// Restore .pre-entire backup if it exists
		if fileExists(backupPath) {
			if hookExists && !hookIsOurs {
				// A non-Entire hook is present — don't overwrite it with the backup
				fmt.Fprintf(os.Stderr, "[entire] Warning: %s was modified since install; backup %s%s left in place\n", hook, hook, backupSuffix)
			} else {
				if err := os.Rename(backupPath, hookPath); err != nil {
					removeErrors = append(removeErrors, fmt.Sprintf("restore %s%s: %v", hook, backupSuffix, err))
				}
			}
		}
	}

	if len(removeErrors) > 0 {
		return removed, fmt.Errorf("failed to remove hooks: %s", strings.Join(removeErrors, "; "))
	}
	return removed, nil
}

// generateChainedContent appends a chain call to the base hook content,
// so the pre-existing hook (backed up to .pre-entire) is called after our hook.
func generateChainedContent(baseContent, hookName string) string {
	return baseContent + fmt.Sprintf(`%s
_entire_hook_dir="$(dirname "$0")"
if [ -x "$_entire_hook_dir/%s%s" ]; then
    "$_entire_hook_dir/%s%s" "$@"
fi
`, chainComment, hookName, backupSuffix, hookName, backupSuffix)
}

// hookCmdPrefix returns the command prefix for hook scripts and warning messages.
// Returns "go run ./cmd/entire/main.go" when local_dev is enabled.
// When absolutePath is true, resolves the full binary path via os.Executable()
// and returns an error if resolution fails. This is needed for GUI git clients
// (Xcode, Tower, etc.) that don't source shell profiles.
func hookCmdPrefix(localDev, absolutePath bool) (string, error) {
	if localDev {
		return "go run ./cmd/entire/main.go", nil
	}
	if absolutePath {
		exe, err := os.Executable()
		if err != nil {
			return "", fmt.Errorf("--absolute-git-hook-path: failed to resolve binary path: %w", err)
		}
		resolved, err := filepath.EvalSymlinks(exe)
		if err != nil {
			return "", fmt.Errorf("--absolute-git-hook-path: failed to resolve symlinks for %s: %w", exe, err)
		}
		return shellQuote(resolved), nil
	}
	return "entire", nil
}

// shellQuote wraps a string in single quotes for safe use in #!/bin/sh scripts.
// Handles paths containing spaces, apostrophes, or other shell metacharacters
// (e.g., /Users/John O'Brien/bin/entire).
func shellQuote(s string) string {
	return "'" + strings.ReplaceAll(s, "'", "'\\''") + "'"
}

// hookSettingsFromConfig loads hook-related settings from .entire/settings.json.
// Returns (localDev, absoluteHookPath). On error, both default to false.
func hookSettingsFromConfig(ctx context.Context) (localDev, absoluteHookPath bool) {
	s, err := settings.Load(ctx)
	if err != nil {
		return false, false
	}
	return s.LocalDev, s.AbsoluteGitHookPath
}

// Package logging provides structured logging for the Entire CLI using slog.
//
// Usage:
//
//	// Initialize logger for a session (typically at session start)
//	if err := logging.Init(sessionID); err != nil {
//	    // handle error
//	}
//	defer logging.Close()
//
//	// Add context values
//	ctx = logging.WithSession(ctx, sessionID)
//	ctx = logging.WithToolCall(ctx, toolCallID)
//
//	// Log with context - session/tool IDs extracted automatically
//	logging.Info(ctx, "hook invoked",
//	    slog.String("hook", hookName),
//	    slog.String("branch", branch),
//	)
package logging

import (
	"bufio"
	"context"
	"fmt"
	"io"
	"log/slog"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/paths"
	"github.com/entireio/cli/cmd/entire/cli/validation"
)

// LogLevelEnvVar is the environment variable that controls log level.
const LogLevelEnvVar = "ENTIRE_LOG_LEVEL"

// LogsDir is the directory where log files are stored (relative to repo root).
const LogsDir = ".entire/logs"

var (
	// logger is the package-level logger instance
	logger *slog.Logger

	// logFile holds the current log file handle for cleanup
	logFile *os.File

	// logBufWriter wraps logFile with buffered I/O for performance
	logBufWriter *bufio.Writer

	// currentSessionID stores the session ID from Init() to include in all logs
	currentSessionID string

	// mu protects logger, logFile, logBufWriter, and currentSessionID
	mu sync.RWMutex

	// logLevelGetter is an optional callback to get log level from settings.
	// Set by SetLogLevelGetter before Init is called.
	logLevelGetter func() string
)

// SetLogLevelGetter sets a callback function to get the log level from settings.
// This allows the logging package to read settings without a circular dependency.
// The callback is only used if ENTIRE_LOG_LEVEL env var is not set.
func SetLogLevelGetter(getter func() string) {
	mu.Lock()
	defer mu.Unlock()
	logLevelGetter = getter
}

// Init initializes the logger for a session, writing JSON logs to
// .entire/logs/entire.log.
//
// If sessionID is non-empty, it is stored as an slog attribute on every log line for filtering.
// If the log file cannot be created, falls back to stderr.
// Log level is controlled by ENTIRE_LOG_LEVEL environment variable.
func Init(ctx context.Context, sessionID string) error {
	// Validate session ID if provided (used only for the slog attribute, not the filename)
	if sessionID != "" {
		if err := validation.ValidateSessionID(sessionID); err != nil {
			return fmt.Errorf("invalid session ID for logging: %w", err)
		}
	}

	mu.Lock()
	defer mu.Unlock()

	// Close any existing log file (flush buffer first)
	if logBufWriter != nil {
		_ = logBufWriter.Flush()
		logBufWriter = nil
	}
	if logFile != nil {
		_ = logFile.Close()
		logFile = nil
	}

	// Get log level from environment first, then settings
	levelStr := os.Getenv(LogLevelEnvVar)
	if levelStr == "" && logLevelGetter != nil {
		levelStr = logLevelGetter()
	}
	level := parseLogLevel(levelStr)

	// Warn if invalid level was provided
	if levelStr != "" && !isValidLogLevel(levelStr) {
		fmt.Fprintf(os.Stderr, "[entire] Warning: invalid log level %q, defaulting to INFO\n", levelStr)
	}

	// Determine log file path
	repoRoot, err := paths.WorktreeRoot(ctx)
	if err != nil {
		// Fall back to current directory
		repoRoot = "."
	}

	logsPath := filepath.Join(repoRoot, LogsDir)
	if err := os.MkdirAll(logsPath, 0o750); err != nil {
		// Fall back to stderr
		logger = createLogger(os.Stderr, level)
		return nil
	}

	logFilePath := filepath.Join(logsPath, "entire.log")
	f, err := os.OpenFile(logFilePath, os.O_CREATE|os.O_APPEND|os.O_WRONLY, 0o600) //nolint:gosec // fixed filename, not user-controlled
	if err != nil {
		// Fall back to stderr
		logger = createLogger(os.Stderr, level)
		return nil
	}

	logFile = f
	logBufWriter = bufio.NewWriterSize(f, 8192) // 8KB buffer for batched writes
	logger = createLogger(logBufWriter, level)
	currentSessionID = sessionID

	return nil
}

// Close closes the log file if one is open.
// Flushes any buffered data before closing.
// Safe to call multiple times.
func Close() {
	mu.Lock()
	defer mu.Unlock()

	if logBufWriter != nil {
		_ = logBufWriter.Flush()
		logBufWriter = nil
	}
	if logFile != nil {
		_ = logFile.Close()
		logFile = nil
	}
	currentSessionID = ""
}

// resetLogger resets the logger to nil (for testing).
func resetLogger() {
	mu.Lock()
	defer mu.Unlock()
	logger = nil
	currentSessionID = ""
	if logBufWriter != nil {
		_ = logBufWriter.Flush()
		logBufWriter = nil
	}
	if logFile != nil {
		_ = logFile.Close()
		logFile = nil
	}
}

// getLogger returns the current logger, or a default stderr logger if not initialized.
func getLogger() *slog.Logger {
	mu.RLock()
	defer mu.RUnlock()

	if logger == nil {
		// Return default stderr logger
		return slog.Default()
	}
	return logger
}

// getSessionID returns the current session ID (thread-safe).
func getSessionID() string {
	mu.RLock()
	defer mu.RUnlock()
	return currentSessionID
}

// createLogger creates a JSON logger writing to the given writer at the specified level.
func createLogger(w io.Writer, level slog.Level) *slog.Logger {
	opts := &slog.HandlerOptions{
		Level: level,
	}
	handler := slog.NewJSONHandler(w, opts)
	return slog.New(handler)
}

// parseLogLevel parses a log level string to slog.Level.
// Returns slog.LevelInfo for empty or invalid values.
func parseLogLevel(s string) slog.Level {
	switch strings.ToUpper(strings.TrimSpace(s)) {
	case "DEBUG":
		return slog.LevelDebug
	case "INFO":
		return slog.LevelInfo
	case "WARN", "WARNING":
		return slog.LevelWarn
	case "ERROR":
		return slog.LevelError
	default:
		return slog.LevelInfo
	}
}

// isValidLogLevel checks if the given string is a valid log level.
func isValidLogLevel(s string) bool {
	switch strings.ToUpper(strings.TrimSpace(s)) {
	case "DEBUG", "INFO", "WARN", "WARNING", "ERROR", "":
		return true
	default:
		return false
	}
}

// Debug logs at DEBUG level with context values automatically extracted.
func Debug(ctx context.Context, msg string, attrs ...any) {
	log(ctx, slog.LevelDebug, msg, attrs...)
}

// Info logs at INFO level with context values automatically extracted.
func Info(ctx context.Context, msg string, attrs ...any) {
	log(ctx, slog.LevelInfo, msg, attrs...)
}

// Warn logs at WARN level with context values automatically extracted.
func Warn(ctx context.Context, msg string, attrs ...any) {
	log(ctx, slog.LevelWarn, msg, attrs...)
}

// Error logs at ERROR level with context values automatically extracted.
func Error(ctx context.Context, msg string, attrs ...any) {
	log(ctx, slog.LevelError, msg, attrs...)
}

// LogDuration logs a message with duration_ms calculated from the start time.
// The level parameter specifies the log level (use slog.LevelDebug, slog.LevelInfo, etc).
// Designed for use with defer:
//
//	defer logging.LogDuration(ctx, slog.LevelInfo, "operation completed", time.Now())
//
// Or with additional attrs:
//
//	defer logging.LogDuration(ctx, slog.LevelDebug, "hook executed", start,
//	    slog.String("hook", hookName),
//	    slog.Bool("success", true),
//	)
func LogDuration(ctx context.Context, level slog.Level, msg string, start time.Time, attrs ...any) {
	durationMs := time.Since(start).Milliseconds()

	// Prepend duration_ms to attrs
	allAttrs := make([]any, 0, len(attrs)+1)
	allAttrs = append(allAttrs, slog.Int64("duration_ms", durationMs))
	allAttrs = append(allAttrs, attrs...)

	log(ctx, level, msg, allAttrs...)
}

// log is the internal logging function that extracts context values and logs.
func log(ctx context.Context, level slog.Level, msg string, attrs ...any) {
	l := getLogger()

	// Build attributes slice with session ID first (if set)
	var allAttrs []any

	// Add session ID from Init() if set (always first for consistency)
	globalSessionID := getSessionID()
	if globalSessionID != "" {
		allAttrs = append(allAttrs, slog.String("session_id", globalSessionID))
	}

	// Extract context values, skipping session_id if already added from Init()
	contextAttrs := attrsFromContext(ctx, globalSessionID)
	for _, a := range contextAttrs {
		allAttrs = append(allAttrs, a)
	}

	// Add caller-provided attributes
	allAttrs = append(allAttrs, attrs...)

	// Pass nil context to slog as we've already extracted context values as attributes.
	// slog handlers are expected to handle nil context gracefully.
	l.Log(nil, level, msg, allAttrs...) //nolint:staticcheck // nil context is intentional - we extract values as attributes
}

// attrsFromContext extracts logging attributes from a context.
// If globalSessionID is non-empty, skips adding session_id from context to avoid duplicates.
func attrsFromContext(ctx context.Context, globalSessionID string) []slog.Attr {
	if ctx == nil {
		return nil
	}

	var attrs []slog.Attr

	// Only add session_id from context if not already set globally
	if globalSessionID == "" {
		if v := ctx.Value(sessionIDKey); v != nil {
			if s, ok := v.(string); ok && s != "" {
				attrs = append(attrs, slog.String("session_id", s))
			}
		}
	}
	if v := ctx.Value(parentSessionIDKey); v != nil {
		if s, ok := v.(string); ok && s != "" {
			attrs = append(attrs, slog.String("parent_session_id", s))
		}
	}
	if v := ctx.Value(toolCallIDKey); v != nil {
		if s, ok := v.(string); ok && s != "" {
			attrs = append(attrs, slog.String("tool_call_id", s))
		}
	}
	if v := ctx.Value(componentKey); v != nil {
		if s, ok := v.(string); ok && s != "" {
			attrs = append(attrs, slog.String("component", s))
		}
	}
	if v := ctx.Value(agentKey); v != nil {
		if s, ok := v.(string); ok && s != "" {
			attrs = append(attrs, slog.String("agent", s))
		}
	}

	return attrs
}

